/// <summary>
/// Controller for populating table metadata for AI agent consumption
/// </summary>
class ARBTableMetadataPopulateController extends SysOperationServiceController
{
}

Method.Source:
/// <summary>
/// Constructor for ARBTableMetadataPopulateController
/// </summary>
/// <param name = "_className">The name of the class</param>
/// <param name = "_methodName">The method name</param>
/// <param name = "_executionMode">The execution mode</param>
protected void new(IdentifierName _className = '', IdentifierName _methodName = '', SysOperationExecutionMode _executionMode = SysOperationExecutionMode::Synchronous)
{
    super(classStr(ARBTableMetadataPopulateService), methodStr(ARBTableMetadataPopulateService, populateTableMetadata), _executionMode);
}

/// <summary>
/// Construct method for ARBTableMetadataPopulateController
/// </summary>
/// <returns>The new ARBTableMetadataPopulateController</returns>
public static ARBTableMetadataPopulateController construct()
{
    return new ARBTableMetadataPopulateController();
}

/// <summary>
/// The main method
/// </summary>
/// <param name = "_args">The arguments</param>
public static void main(Args _args)
{
    ARBTableMetadataPopulateController controller = ARBTableMetadataPopulateController::construct();

    controller.startOperation();
}

/// <summary>
/// The caption for the controller
/// </summary>
/// <returns>The caption</returns>
public ClassDescription caption()
{
    return "@AOTBrowser:PopulateTableMetadata";
}

/// <summary>
/// The dialog caption
/// </summary>
/// <param name = "_dialogCaption">The new dialog caption</param>
/// <returns>The dialog caption</returns>
public LabelType parmDialogCaption(LabelType _dialogCaption = dialogCaption)
{
    LabelType ret;

    ret = "@AOTBrowser:PopulateTableMetadata";

    return ret;
}
